/// <summary>
/// Extension of the methods of the <c>CustTable</c> table for the ETGSPAIN model.
/// </summary>
[ExtensionOf(tableStr(CustTable))]
final class CustTable_Table_ETGSPAIN_Extension
{
}

Method.Source:
/// <summary>
/// Method to regenerate the numeric sequence of the table.
/// </summary>
/// <returns>The generated <c>CustAccount</c>.</returns>
public CustAccount ETGSPAINGenerateCustAccount()
{
    CustAccount ret;
    str         range;
    CustTable   custTable;

    ret += "C";
    ret += "_";
    ret += this.CustGroup;
    ret += "_";
    ret += this.DataAreaId;
    ret += "_";                            
    ret += this.ETGSPAINSalesPurchPartyCountry;

    range = strFmt("%1*", ret);

    select firstonly count(RecId) from custTable
        order by AccountNum desc
        where custTable.AccountNum like range
            && custTable.AccountNum != ret;

    System.Int64    numberOfRecords     = custTable.RecId + 1;
    String10        numberOfRecordsStr  = numberOfRecords.ToString("D3");

    ret += strFmt("_%1", numberOfRecordsStr);


    return strUpr(ret);
}
